import React from 'react';
import { graphql } from 'gatsby';
import Layout from '../components/layout';
import SEO from '../components/seo';
import Image from 'gatsby-image';

const BeerCollection = ({ data, location }) => {
  const siteTitle = data.site.siteMetadata?.title || `Title`;

  return (
    <Layout location={location} title={siteTitle}>
      <SEO title="Beer Can Collection" />

      <h1>Beer Can Collection</h1>
      <p>My collection of beer cans, including some different products.</p>

      <div className="beer-container">
        {data.allFile.edges.map((image, index) => {
          const title = image.node.base.split('.')[0];
          console.log(title)
          return <Image
            fluid={image.node.childImageSharp.fluid}
            alt={title}
            key={index}
            title={title}
            fadeIn={true}
          />
        })}
      </div>
    </Layout>
  )
}

export default BeerCollection;

export const pageQuery = graphql`
  query {
    allFile (
      filter: {
        extension: { regex: "/(jpg)|(png)|(jpeg)/" }
        relativeDirectory: { eq: "beer" }
      }
    ) {
      edges {
        node {
          base
          childImageSharp {
            fluid {
              base64
              aspectRatio
              src
              srcSet
              sizes
            }
          }
        }
      }
    }

    site {
      siteMetadata {
        title
      }
    }

    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      nodes {
        excerpt
        fields {
          slug
        }
        frontmatter {
          date(formatString: "MMMM DD, YYYY")
          title
          description
          isTranslation
        }
      }
    }
  }
`;
